import hashlib

with open('/app/code.png', 'rb') as f:
    img_bytes = f.read()

h0 = hashlib.sha256(img_bytes).digest()

salts = [b"0000TBENCH-SALT", b"0000TBENCH-SALT\n", b"0000TBENCH-SALT\r\n"]

for salt in salts:
    for h0_part in [h0[-10:], h0[:10]]:
        H = hashlib.sha256(h0 + h0_part + salt).hexdigest()
        if H.startswith('bee26a'):
            print(f"Bytes: {H}")

h0_hex = hashlib.sha256(img_bytes).hexdigest().encode()
for salt in salts:
    for h0_part in [h0_hex[-10:], h0_hex[:10]]:
        H = hashlib.sha256(h0_hex + h0_part + salt).hexdigest()
        if H.startswith('bee26a'):
            print(f"Hex: {H}")
